mapper.select:
    	/* com.erns.coching.common.file.mapper.ProxyFileDAO.getList */

			SELECT

			FROM T_PROXY_FILE AA


				AND AA.DEL_YN = 'N'



				OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.common.file.mapper.ProxyFileDAO.getListCount */
SELECT COUNT(*) FROM T_PROXY_FILE AA
AND AA.DEL_YN = 'N'

    	/* com.erns.coching.common.file.mapper.ProxyFileDAO.load */

			SELECT

			FROM T_PROXY_FILE AA

				AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

			LIMIT 1

    	/* com.erns.coching.common.file.mapper.ProxyFileDAO.loadVo */

			SELECT

			FROM T_PROXY_FILE AA

				AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

			LIMIT 1

    	/* com.erns.coching.common.file.mapper.ProxyFileDAO.loadVoByOrgUrl */

			SELECT

			FROM T_PROXY_FILE AA

				AND AA.ORG_URL = #{orgUrl , jdbcType=VARCHAR}

			LIMIT 1

mapper.insert:
    	/* com.erns.coching.common.file.mapper.ProxyFileDAO.insert */

    	INSERT INTO T_PROXY_FILE (
						FILE_ID
					, REF_CODE
					, ORG_URL

					, FILE_NAME
					, FILE_EXT
					, FILE_NAME_DEST
					, FILE_PATH
					, FILE_SIZE
					, DEL_YN

					, RGTR
					, RGT_DTTM
					, CHNR
					, CHNG_DTTM
				) VALUES (
						#{fileId		, jdbcType=VARCHAR}
					, #{refCode		, jdbcType=VARCHAR}
					, #{orgUrl		, jdbcType=VARCHAR}

					, #{fileName	, jdbcType=VARCHAR}
					, #{fileExt		, jdbcType=VARCHAR}
					, #{fileNameDest, jdbcType=VARCHAR}
					, #{filePath	, jdbcType=VARCHAR}
					, #{fileSize	, jdbcType=INTEGER}
					, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

					, #{rgtr		, jdbcType=INTEGER}
					, now()
					, #{chnr		, jdbcType=INTEGER}
					, now()
				)

mapper.update:
/* com.erns.coching.common.file.mapper.ProxyFileDAO.updateDelYn */

UPDATE T_PROXY_FILE SET
		DEL_YN 		= #{delYn, jdbcType=CHAR}

	, CHNR 		= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND FILE_ID = #{fileId, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.common.file.mapper.ProxyFileDAO.deleteByOrgUrl */

DELETE FROM T_PROXY_FILE

	AND ORG_URL = #{orgUrl, jdbcType=VARCHAR}
